import type * as DMMF from '@prisma/dmmf'

/** Maps Prisma scalar type names to their TypeScript equivalents. */
const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/**
 * Converts a DMMF field to its TypeScript type string.
 *
 * Returns an empty string for relation (`object`) and `unsupported` fields,
 * which the caller should treat as a signal to skip the field entirely.
 */
export function dmmfFieldToTsType(field: Pick<DMMF.Field, 'kind' | 'type' | 'isList'>): string {
  let baseType: string

  if (field.kind === 'scalar') {
    baseType = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  } else if (field.kind === 'enum') {
    baseType = field.type
  } else {
    return ''
  }

  return field.isList ? `${baseType}[]` : baseType
}

