import type * as DMMF from '@prisma/dmmf'
import pluralize from 'pluralize'

import { dmmfFieldToTsType } from './dmmf-to-ts-type'

/** Returns the REST resource path segment for a model, e.g. `User` → `/users`. */
export function modelToResourcePath(modelName: string): string {
  return `/${pluralize(modelName.charAt(0).toLowerCase() + modelName.slice(1))}`
}

/** Returns only scalar and enum fields, filtering out relations and unsupported types. */
function dataFields(model: DMMF.Model): DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
}

/** Returns scalar/enum fields that identify a unique record (id or unique). */
function uniqueScalarFields(model: DMMF.Model): DMMF.Field[] {
  return dataFields(model).filter((f) => f.isId || f.isUnique)
}

/**
 * Generates the TypeScript interface representing a model's persisted shape.
 * Only scalar and enum fields are included; relation fields are omitted.
 */
export function generateModelInterface(model: DMMF.Model): string {
  const lines = dataFields(model).map((f) => {
    const tsType = dmmfFieldToTsType(f)
    const optional = f.isRequired ? '' : '?'
    return `  ${f.name}${optional}: ${tsType}`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Generates the input type for create operations.
 * Id fields and read-only fields are excluded; fields with defaults become optional.
 */
export function generateCreateInput(model: DMMF.Model): string {
  const fields = dataFields(model).filter((f) => !f.isReadOnly && !f.isId)
  const lines = fields.map((f) => {
    const tsType = dmmfFieldToTsType(f)
    const optional = f.isRequired && !f.hasDefaultValue ? '' : '?'
    return `  ${f.name}${optional}: ${tsType}`
  })
  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates the input type for update operations.
 * Every field is optional since partial updates are the norm in REST PATCH semantics.
 */
export function generateUpdateInput(model: DMMF.Model): string {
  const fields = dataFields(model).filter((f) => !f.isReadOnly && !f.isId)
  const lines = fields.map((f) => {
    const tsType = dmmfFieldToTsType(f)
    return `  ${f.name}?: ${tsType}`
  })
  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates the input type used to locate a single record by its unique key(s).
 * All fields are optional so callers can choose whichever unique key they have.
 */
export function generateWhereUniqueInput(model: DMMF.Model): string {
  const fields = uniqueScalarFields(model)
  const lines = fields.map((f) => {
    const tsType = dmmfFieldToTsType(f)
    return `  ${f.name}?: ${tsType}`
  })
  return `export interface ${model.name}WhereUniqueInput {\n${lines.join('\n')}\n}`
}

/**
 * Generates a typed client class for a single Prisma model.
 *
 * The class exposes five CRUD methods that map to standard REST conventions:
 *   - `findMany`  → GET  /<resources>
 *   - `findUnique`→ GET  /<resources>/findUnique?<params>
 *   - `create`    → POST /<resources>
 *   - `update`    → PATCH /<resources>?<params>
 *   - `delete`    → DELETE /<resources>?<params>
 */
export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const path = modelToResourcePath(name)

  return `export class ${name}Client {
  #baseUrl: string
  #init: RequestInit | undefined

  constructor(baseUrl: string, init?: RequestInit) {
    this.#baseUrl = baseUrl
    this.#init = init
  }

  async findMany(): Promise<${name}[]> {
    const res = await fetch(\`\${this.#baseUrl}${path}\`, {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
      ...this.#init,
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${await res.text()}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const params = new URLSearchParams(where as Record<string, string>)
    const res = await fetch(\`\${this.#baseUrl}${path}/findUnique?\${params}\`, {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
      ...this.#init,
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${await res.text()}\`)
    return res.json() as Promise<${name} | null>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await fetch(\`\${this.#baseUrl}${path}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
      ...this.#init,
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${await res.text()}\`)
    return res.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const params = new URLSearchParams(where as Record<string, string>)
    const res = await fetch(\`\${this.#baseUrl}${path}?\${params}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
      ...this.#init,
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${await res.text()}\`)
    return res.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const params = new URLSearchParams(where as Record<string, string>)
    const res = await fetch(\`\${this.#baseUrl}${path}?\${params}\`, {
      method: 'DELETE',
      headers: { 'Content-Type': 'application/json' },
      ...this.#init,
    })
    if (!res.ok) throw new Error(\`HTTP \${res.status}: \${await res.text()}\`)
    return res.json() as Promise<${name}>
  }
}`
}

