import fs from 'node:fs'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import {
  generateCreateInput,
  generateModelClient,
  generateModelInterface,
  generateUpdateInput,
  generateWhereUniqueInput,
} from './generate-model'

const FILE_HEADER = `\
// ============================================================
// Generated by @prisma/client-generator-rest
// DO NOT EDIT — this file is auto-generated.
// ============================================================
`

/**
 * Generates the full REST client source tree and writes it to `outputDir`.
 *
 * For each model in the DMMF datamodel the following are emitted:
 *   - A `<Model>` interface (scalar/enum fields only)
 *   - A `<Model>CreateInput` interface
 *   - A `<Model>UpdateInput` interface
 *   - A `<Model>WhereUniqueInput` interface
 *   - A `<Model>Client` class with `findMany`, `findUnique`, `create`, `update`, `delete`
 *
 * A top-level `PrismaRestClient` class ties all per-model clients together under
 * camelCase property names (e.g. `client.user`, `client.blogPost`).
 *
 * Prisma enums are emitted as TypeScript `const enum` declarations so the generated
 * file is self-contained and requires no runtime imports.
 */
export function generateRestClient(dmmf: DMMF.Document, outputDir: string): void {
  const { models, enums } = dmmf.datamodel
  const sections: string[] = [FILE_HEADER]

  if (enums.length > 0) {
    sections.push('// ─── Enums ────────────────────────────────────────────────────\n')
    for (const e of enums) {
      const values = e.values.map((v) => `  ${v.name} = '${v.name}'`).join(',\n')
      sections.push(`export const enum ${e.name} {\n${values}\n}`)
    }
  }

  sections.push('// ─── Model interfaces & input types ──────────────────────────\n')
  for (const model of models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateWhereUniqueInput(model))
  }

  sections.push('// ─── Per-model REST clients ───────────────────────────────────\n')
  for (const model of models) {
    sections.push(generateModelClient(model))
  }

  sections.push('// ─── PrismaRestClient ─────────────────────────────────────────\n')

  const clientProps = models
    .map((m) => {
      const prop = toCamelCase(m.name)
      return `  readonly ${prop}: ${m.name}Client`
    })
    .join('\n')

  const ctorAssignments = models
    .map((m) => {
      const prop = toCamelCase(m.name)
      return `    this.${prop} = new ${m.name}Client(baseUrl, init)`
    })
    .join('\n')

  sections.push(
    `export class PrismaRestClient {\n${clientProps}\n\n  constructor(baseUrl: string, init?: RequestInit) {\n${ctorAssignments}\n  }\n}`,
  )

  const output = sections.join('\n\n')
  fs.mkdirSync(outputDir, { recursive: true })
  fs.writeFileSync(path.join(outputDir, 'index.ts'), output, 'utf-8')
}

function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

