import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './generate-client'

/**
 * Prisma generator that produces a typed REST API client from the Prisma schema.
 *
 * Add it to your schema with:
 *
 * ```prisma
 * generator restClient {
 *   provider = "prisma-client-generator-rest"
 *   output   = "./generated/rest-client"
 * }
 * ```
 *
 * The generator writes a single `index.ts` file to the configured output directory.
 * That file contains:
 *   - TypeScript interfaces for every model
 *   - `CreateInput`, `UpdateInput`, and `WhereUniqueInput` types per model
 *   - Per-model client classes with `findMany`, `findUnique`, `create`, `update`, `delete`
 *   - A `PrismaRestClient` class that aggregates all per-model clients
 */
export class RestApiGenerator implements Generator {
  readonly name = 'prisma-client-generator-rest'

  async getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      prettyName: 'Prisma REST API Client',
      defaultOutput: './generated/rest-client',
      requiresEngines: [],
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value
    if (!outputDir) {
      throw new Error(
        'No output path configured for @prisma/client-generator-rest. ' +
          'Set `output` in your generator block or rely on the default `./generated/rest-client`.',
      )
    }

    generateRestClient(options.dmmf, outputDir)
  }
}

