import { describe, expect, test } from 'vitest'

import { dmmfFieldToTsType } from '../dmmf-to-ts-type'

describe('dmmfFieldToTsType', () => {
  test.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['BigInt', 'bigint'],
    ['Decimal', 'string'],
    ['DateTime', 'string'],
    ['Json', 'unknown'],
    ['Bytes', 'string'],
  ])('maps scalar %s → %s', (prismaType, tsType) => {
    expect(dmmfFieldToTsType({ kind: 'scalar', type: prismaType, isList: false })).toBe(tsType)
  })

  test('wraps type in array notation when isList is true', () => {
    expect(dmmfFieldToTsType({ kind: 'scalar', type: 'Int', isList: true })).toBe('number[]')
    expect(dmmfFieldToTsType({ kind: 'scalar', type: 'String', isList: true })).toBe('string[]')
  })

  test('maps enum kind to the enum type name', () => {
    expect(dmmfFieldToTsType({ kind: 'enum', type: 'Role', isList: false })).toBe('Role')
    expect(dmmfFieldToTsType({ kind: 'enum', type: 'Status', isList: true })).toBe('Status[]')
  })

  test('returns empty string for relation (object) fields', () => {
    expect(dmmfFieldToTsType({ kind: 'object', type: 'Post', isList: true })).toBe('')
    expect(dmmfFieldToTsType({ kind: 'object', type: 'User', isList: false })).toBe('')
  })

  test('returns empty string for unsupported fields', () => {
    expect(dmmfFieldToTsType({ kind: 'unsupported', type: 'geometry', isList: false })).toBe('')
  })

  test('falls back to unknown for unrecognised scalar types', () => {
    expect(dmmfFieldToTsType({ kind: 'scalar', type: 'UnknownType', isList: false })).toBe('unknown')
  })
})

