import { describe, expect, test } from 'vitest'

import type * as DMMF from '@prisma/dmmf'

import {
  generateCreateInput,
  generateModelClient,
  generateModelInterface,
  generateUpdateInput,
  generateWhereUniqueInput,
  modelToResourcePath,
} from '../generate-model'

// ---------------------------------------------------------------------------
// Fixtures
// ---------------------------------------------------------------------------

const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    {
      kind: 'scalar',
      name: 'id',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: true,
      isReadOnly: false,
      type: 'Int',
      hasDefaultValue: true,
      default: { name: 'autoincrement', args: [] },
    },
    {
      kind: 'scalar',
      name: 'email',
      isRequired: true,
      isList: false,
      isUnique: true,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'scalar',
      name: 'name',
      isRequired: false,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'object',
      name: 'posts',
      isRequired: false,
      isList: true,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'Post',
      hasDefaultValue: false,
      relationName: 'PostToUser',
    },
  ],
  uniqueFields: [['email']],
  uniqueIndexes: [{ name: null, fields: ['email'] }],
  primaryKey: null,
}

// ---------------------------------------------------------------------------
// modelToResourcePath
// ---------------------------------------------------------------------------

describe('modelToResourcePath', () => {
  test('lowercases and pluralizes the model name', () => {
    expect(modelToResourcePath('User')).toBe('/users')
    expect(modelToResourcePath('Post')).toBe('/posts')
    expect(modelToResourcePath('BlogPost')).toBe('/blogPosts')
  })
})

// ---------------------------------------------------------------------------
// generateModelInterface
// ---------------------------------------------------------------------------

describe('generateModelInterface', () => {
  test('emits only scalar fields, marks optional fields with ?', () => {
    const result = generateModelInterface(userModel)
    expect(result).toContain('export interface User {')
    expect(result).toContain('  id: number')
    expect(result).toContain('  email: string')
    expect(result).toContain('  name?: string')
    // relation field must be absent
    expect(result).not.toContain('posts')
  })
})

// ---------------------------------------------------------------------------
// generateCreateInput
// ---------------------------------------------------------------------------

describe('generateCreateInput', () => {
  test('excludes id and read-only fields', () => {
    const result = generateCreateInput(userModel)
    expect(result).toContain('export interface UserCreateInput {')
    expect(result).not.toContain('  id')
  })

  test('required fields without defaults remain required', () => {
    const result = generateCreateInput(userModel)
    // email is required, no default → must not have ?
    expect(result).toContain('  email: string')
  })

  test('optional fields and fields with defaults become optional', () => {
    const result = generateCreateInput(userModel)
    expect(result).toContain('  name?: string')
  })
})

// ---------------------------------------------------------------------------
// generateUpdateInput
// ---------------------------------------------------------------------------

describe('generateUpdateInput', () => {
  test('all writable fields are optional', () => {
    const result = generateUpdateInput(userModel)
    expect(result).toContain('export interface UserUpdateInput {')
    expect(result).toContain('  email?: string')
    expect(result).toContain('  name?: string')
    expect(result).not.toContain('  id')
  })
})

// ---------------------------------------------------------------------------
// generateWhereUniqueInput
// ---------------------------------------------------------------------------

describe('generateWhereUniqueInput', () => {
  test('includes id and @unique scalar fields, all optional', () => {
    const result = generateWhereUniqueInput(userModel)
    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('  id?: number')
    expect(result).toContain('  email?: string')
    // non-unique name field must be absent
    expect(result).not.toContain('  name')
  })
})

// ---------------------------------------------------------------------------
// generateModelClient
// ---------------------------------------------------------------------------

describe('generateModelClient', () => {
  test('emits a class with all five CRUD methods', () => {
    const result = generateModelClient(userModel)
    expect(result).toContain('export class UserClient {')
    expect(result).toContain('async findMany()')
    expect(result).toContain('async findUnique(where: UserWhereUniqueInput)')
    expect(result).toContain('async create(data: UserCreateInput)')
    expect(result).toContain('async update(where: UserWhereUniqueInput, data: UserUpdateInput)')
    expect(result).toContain('async delete(where: UserWhereUniqueInput)')
  })

  test('uses the correct REST resource path', () => {
    const result = generateModelClient(userModel)
    expect(result).toContain('/users')
  })

  test('uses native private fields (#)', () => {
    const result = generateModelClient(userModel)
    expect(result).toContain('#baseUrl')
    expect(result).toContain('#init')
  })

  test('throws on non-ok responses', () => {
    const result = generateModelClient(userModel)
    expect(result).toContain('if (!res.ok)')
    expect(result).toContain('throw new Error')
  })
})

