import type * as DMMF from '@prisma/dmmf'
import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import { generateRestClient } from '../generate-client'

// ---------------------------------------------------------------------------
// Fixtures
// ---------------------------------------------------------------------------

const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    {
      kind: 'scalar',
      name: 'id',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: true,
      isReadOnly: false,
      type: 'Int',
      hasDefaultValue: true,
      default: { name: 'autoincrement', args: [] },
    },
    {
      kind: 'scalar',
      name: 'email',
      isRequired: true,
      isList: false,
      isUnique: true,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
  ],
  uniqueFields: [['email']],
  uniqueIndexes: [{ name: null, fields: ['email'] }],
  primaryKey: null,
}

const postModel: DMMF.Model = {
  name: 'Post',
  dbName: null,
  schema: null,
  fields: [
    {
      kind: 'scalar',
      name: 'id',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: true,
      isReadOnly: false,
      type: 'Int',
      hasDefaultValue: true,
      default: { name: 'autoincrement', args: [] },
    },
    {
      kind: 'scalar',
      name: 'title',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'scalar',
      name: 'authorId',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: true,
      type: 'Int',
      hasDefaultValue: false,
    },
    {
      kind: 'object',
      name: 'author',
      isRequired: false,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'User',
      hasDefaultValue: false,
      relationName: 'PostToUser',
    },
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
}

const roleEnum: DMMF.DatamodelEnum = {
  name: 'Role',
  values: [
    { name: 'ADMIN', dbName: null },
    { name: 'USER', dbName: null },
  ],
}

function makeDmmf(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: { models, enums, types: [], indexes: [] },
    schema: {
      inputObjectTypes: { prisma: [], model: [] },
      outputObjectTypes: { prisma: [], model: [] },
      enumTypes: { prisma: [], model: [] },
      fieldRefTypes: { prisma: [] },
    } as unknown as DMMF.Schema,
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

let tmpDir: string

beforeEach(() => {
  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'rest-client-test-'))
})

afterEach(() => {
  fs.rmSync(tmpDir, { recursive: true, force: true })
})

function readOutput(): string {
  return fs.readFileSync(path.join(tmpDir, 'index.ts'), 'utf-8')
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('generateRestClient', () => {
  test('creates the output directory and writes index.ts', () => {
    const nestedDir = path.join(tmpDir, 'nested', 'output')
    generateRestClient(makeDmmf([userModel]), nestedDir)
    expect(fs.existsSync(path.join(nestedDir, 'index.ts'))).toBe(true)
  })

  test('emits the auto-generated file header', () => {
    generateRestClient(makeDmmf([userModel]), tmpDir)
    expect(readOutput()).toContain('Generated by @prisma/client-generator-rest')
    expect(readOutput()).toContain('DO NOT EDIT')
  })

  test('emits enum declarations when the schema has enums', () => {
    generateRestClient(makeDmmf([userModel], [roleEnum]), tmpDir)
    const content = readOutput()
    expect(content).toContain("export const enum Role {")
    expect(content).toContain("  ADMIN = 'ADMIN'")
    expect(content).toContain("  USER = 'USER'")
  })

  test('emits no enum section when the schema has no enums', () => {
    generateRestClient(makeDmmf([userModel]), tmpDir)
    expect(readOutput()).not.toContain('const enum')
  })

  test('emits all four interface types for each model', () => {
    generateRestClient(makeDmmf([userModel, postModel]), tmpDir)
    const content = readOutput()

    for (const model of ['User', 'Post']) {
      expect(content).toContain(`export interface ${model} {`)
      expect(content).toContain(`export interface ${model}CreateInput {`)
      expect(content).toContain(`export interface ${model}UpdateInput {`)
      expect(content).toContain(`export interface ${model}WhereUniqueInput {`)
    }
  })

  test('emits a client class for each model', () => {
    generateRestClient(makeDmmf([userModel, postModel]), tmpDir)
    const content = readOutput()
    expect(content).toContain('export class UserClient {')
    expect(content).toContain('export class PostClient {')
  })

  test('emits PrismaRestClient with camelCase properties for every model', () => {
    generateRestClient(makeDmmf([userModel, postModel]), tmpDir)
    const content = readOutput()
    expect(content).toContain('export class PrismaRestClient {')
    expect(content).toContain('readonly user: UserClient')
    expect(content).toContain('readonly post: PostClient')
  })

  test('constructor assigns all model clients', () => {
    generateRestClient(makeDmmf([userModel, postModel]), tmpDir)
    const content = readOutput()
    expect(content).toContain('this.user = new UserClient(baseUrl, init)')
    expect(content).toContain('this.post = new PostClient(baseUrl, init)')
  })

  test('read-only relation field (author) is excluded from PostCreateInput', () => {
    generateRestClient(makeDmmf([postModel]), tmpDir)
    const content = readOutput()
    // authorId is readOnly, author is a relation — neither should appear in CreateInput
    expect(content).not.toContain('  authorId')
    expect(content).not.toContain('  author')
  })
})

